resource "aws_iam_role" "synthetic_role_013" {
  name = "synthetic_role_013"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "synthetic_role_013_policy" {
  name   = "synthetic_role_013-policy"
  role   = aws_iam_role.synthetic_role_013.id
  policy = jsonencode({
    "Version": "2012-10-17",
    "Statement": [
        {
            "Effect": "Allow",
            "Action": [
                "rds:ModifyDBInstance",
                "rds:CreateDBInstance",
                "rds:DescribeDBInstances"
            ],
            "Resource": "arn:aws:iam::*:*"
        }
    ]
})
}
